const items = $input.all();

const filename = $('Decompress Creative1').first().json.filename;

const clean = filename
  .replace(/\.zip$/i, '')
  .replace(/^.*?\s*-\s*/, '')
  .replace(/\s*\(.*?\)/g, '')
  .replace(/\s*\d+\s*$/, '')
  .trim();

return items.map(item => ({
  json: {
    ...item.json,
    cleanName: clean
  }
}));

const item = $json;
const attachments = item.fields?.attachment || [];

function decodeFileName(name) {
  if (!name) return null;
  try { return decodeURIComponent(name.replace(/\+/g, ' ')); } catch (e) { return name; }
}

function getType(name) {
  if (!name) return 'unknown';
  const decoded = decodeFileName(name).toLowerCase();
  if (decoded.includes('креатив') || decoded.includes('creative')) return 'creative';
  if (decoded.includes('дизайн') || decoded.includes('design')) return 'design';
  return 'unknown';
}

let design = null;
let creative = null;

for (const att of attachments) {
  const type = getType(att.name || att.filename || '');
  if (type === 'design' && !design) design = att;
  else if (type === 'creative' && !creative) creative = att;
}

if (!design) design = attachments[0] || null;
if (!creative) creative = attachments[1] || null;

return {
  json: {
    ...item,
    designContent: design ? design.content || null : null,
    designId: design ? design.id || null : null,
    designName: design ? decodeFileName(design.name || design.filename) : null,
    creativeContent: creative ? creative.content || null : null,
    creativeId: creative ? creative.id || null : null,
    creativeName: creative ? decodeFileName(creative.name || creative.filename) : null,
  }
};

