  return name
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/[''`]/g, "'")
    .replace(/\s*[-–—]\s*/g, ' - ')
    .replace(/^\d+\.\s*/, '')
