  const page = pagesIndex[pageId];
  if (page.name && page.name.toLowerCase().includes('контент')) {
    const objects = page.objects || {};
    for (const objId in objects) {
      const obj = objects[objId];
      if (obj.name && obj.name.trim()) {
        existingNames.push(normalizeName(obj.name));
      }
    }
    break;
  }
}

