  const name = normalizeName(item.json.name || '');
  const fileName = normalizeName(
    'Экран ' + (item.json.screenNumber || 0) + ' ' +
    (item.json.name || '')
  );
  return !existingNames.includes(name) && !existingNames.includes(fileName);
});

if (filtered.length === 0) {
  return [{ json: { allDone: true } }];
}

return filtered;

