const filename = $('Download Design ZIP1').first().json.filename || '';
const parsed = filename.slice(6, -4).toLowerCase();

const STYLES = {
  gacha: {
    keyword: 'gacha',
    name: 'gacha',
    needsReference: true,
    description: 'Character style (YOU SHOULD MAKE FULLY DIFFERENT CHARACTER IN THE SAME STYLES): custom character in semi-chibi proportions, match the art style and rendering technique from the provided reference image.'
  }
};

let style = 'colorful game art, high quality digital illustration, vibrant colors';
let styleName = 'default';
let needsReference = false;

for (const key in STYLES) {
  if (parsed.includes(STYLES[key].keyword)) {
    style = STYLES[key].description;
    styleName = STYLES[key].name;
    needsReference = STYLES[key].needsReference;
    break;
  }
}

// Возвращаем ВСЕ items с добавленными полями
return $input.all().map(item => ({
  json: {
    ...item.json,
    styleDescription: style,
    styleName,
    needsReference
  }
}));

