// Code: Check All Ready

const items = $input.all();

// Счётчик попыток
const prevPollCount = items[0]?.json.pollCount || 0;
const pollCount = prevPollCount + 1;
const MAX_POLLS = 10;

// Анализируем статусы
const results = items.map(item => {
  const data = item.json.data || item.json;
  const taskId = data.taskId || item.json.taskId;
  const state = data.state;

  let finalState;
  if (state === 'success') {
    finalState = 'success';
  } else if (state === 'fail') {
    finalState = 'fail';
  } else if (pollCount >= MAX_POLLS) {
    finalState = 'timeout_fail';
  } else {
    finalState = 'waiting';
  }

  return {
    taskId,
    state: finalState,
    resultJson: data.resultJson
  };
});

// Считаем
const successCount = results.filter(r => r.state === 'success').length;
const failCount = results.filter(r => r.state === 'fail' || r.state === 'timeout_fail').length;
const waitingCount = results.filter(r => r.state === 'waiting').length;

const allFinished = waitingCount === 0;

// Возвращаем отдельный item для каждого taskId
return results.map(r => ({
  json: {
    data: {
      taskId: r.taskId,
      state: r.state,
      resultJson: r.resultJson
    },
    allFinished,
    pollCount,
    successCount,
    failCount,
    waitingCount
  }
}));

